const item = $input.first();
const aiRaw = item.json.content.parts[0].text;

const cleaned = aiRaw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```\s*$/i, '')
  .trim();

const parsed = JSON.parse(cleaned);

return [{
  json: {
    score: parsed.score,
    decision: parsed.decision,
    candidate_name: parsed.candidate_name,
    summary: parsed.summary,
    key_skills: parsed.key_skills,
    candidate_email: $('Watch Inbox for CV Emails').first().json.from.value[0].address,
    original_subject: $('Watch Inbox for CV Emails').first().json.subject
  },
  binary: $('Watch Inbox for CV Emails').first().binary
}];
